script_dir = os.path.dirname(os.path.realpath(__file__))
# Move one directory up
parent_dir = os.path.dirname(script_dir)
assets_dir = os.path.join(parent_dir, "assets/")

LOGS_PER_SEC = 100  # 100 logs every second or 100Hz sampling frequency

LOGGING_INTERVAL = 1000 // min(LOGS_PER_SEC, 1000)  # integer division, (1000ms = 1s)


class UserWindow(QMainWindow):
    def __init__(self, stacked_widget, teensy_controller, data_logger):
        super().__init__()
        self.stacked_widget = stacked_widget
        self.teensy_controller = teensy_controller

        # data logger
        self.logging = False
        self.data_logger = data_logger
        self.logger_timmer = QTimer()
        self.logger_timmer.timeout.connect(self.data_logger.log)

        # Intialize variables
        self.carriage_state = "Front-Wheel Drive"
        self.setupUi()

        # Start joystick monitoring thread
        self.joystick_thread = JoystickThread()
        self.joystick_thread.forward_signal.connect(self.handle_forward_movement)
        self.joystick_thread.reverse_signal.connect(self.handle_reverse_movement)
        self.joystick_thread.left_signal.connect(self.handle_left_movement)
        self.joystick_thread.right_signal.connect(self.handle_right_movement)

        # Connect the neutral signal to the function
        self.joystick_thread.neutral_signal.connect(self.handle_neutral_movement)
        self.joystick_thread.start()

    def to_dev_mode(self):
        try:
            # Set to Dev Screen (screen 1)
            self.stacked_widget.setCurrentIndex(1)
        except Exception as e:
            print("Error in to_dev_mode:", e)
            traceback.print_exc()

    def start_logging(self):
        self.data_logger.start()
        self.logger_timmer.start(LOGGING_INTERVAL)

    def stop_logging(self):
        if self.logging is False:
            return
        self.logger_timmer.stop()
        self.data_logger.stop()

    def handle_logging(self):
        if self.logging is False:
            self.log_data_btn.setText("Stop Log")
            self.log_data_btn.setBackgroundColor("LightRed")
            self.start_logging()
            self.logging = True
        else:
            self.log_data_btn.setText("Start Log")
            self.log_data_btn.setBackgroundColor("Default")
            self.stop_logging()
            self.logging = False

    def exit_screen(self):
        try:
            sender_button = self.sender()
            if sender_button == self.exitButton:
                # Cleanup on exit
                self.teensy_controller.reset()

                self.stop_logging()

                QApplication.quit()
        except Exception as e:
            print("Error in exit_screen:", e)
            traceback.print_exc()

