    def handle_neutral_movement(self):
        self.teensy_controller.send_neutral_signal_to_teensy()
        self.update_button_color_flag = True
        self.update_button_color("Neutral")

    def handle_forward_movement(self):
        try:
            # self.update_label_text() # Update label text after button change
            self.update_button_color_flag = True
            self.update_button_color("Forward")

            print("Forward joystick movement detected")
            if self.current_button == self.elevate_btn:
                self.teensy_controller.raise_up_pressed()
            elif self.current_button == self.lean_btn:
                self.teensy_controller.tilt_forward_pressed()
            elif self.current_button == self.tilt_btn:
                self.teensy_controller.tilt_left_pressed()
            elif self.current_button == self.carriage_btn:
                self.carriage_forward_pressed()
            elif self.current_button == self.curb_ascend_btn:
                self.teensy_controller.curb_climb_automation()
            elif self.current_button == self.self_leveling_btn:
                self.teensy_controller.self_leveling_pressed()
            elif self.current_button == self.reset_btn:
                self.teensy_controller.reset()
            elif self.current_button == self.dev_mode_btn:
                self.to_dev_mode()
        except Exception as e:
            print("Error in handle_forward_movement:", e)
            traceback.print_exc()

    def handle_reverse_movement(self):
        try:
            # self.update_label_text() # Update label text after button change
            self.update_button_color_flag = True
            self.update_button_color("Reverse")

            print("Reverse joystick movement detected")
            if self.current_button == self.elevate_btn:
                self.teensy_controller.lower_down_pressed()
            elif self.current_button == self.lean_btn:
                self.teensy_controller.tilt_backward_pressed()
            elif self.current_button == self.tilt_btn:
                self.teensy_controller.tilt_right_pressed()
            elif self.current_button == self.carriage_btn:
                self.carriage_backward_pressed()
            elif self.current_button == self.curb_ascend_btn:
                self.teensy_controller.reset()
            elif self.current_button == self.self_leveling_btn:
                self.teensy_controller.self_leveling_pressed()
            elif self.current_button == self.reset_btn:
                self.teensy_controller.reset()
            elif self.current_button == self.dev_mode_btn:
                self.to_dev_mode()
        except Exception as e:
            print("Error in handle_reverse_movement:", e)
            traceback.print_exc()

