    def update_button_color(self, direction):
        try:
            # Check if button color needs to be updated based on user input
            if not self.update_button_color_flag:
                return

            # Define the list of buttons in the order they should cycle
            buttons = [
                self.elevate_btn,
                self.lean_btn,
                self.tilt_btn,
                self.carriage_btn,
                self.self_leveling_btn,
                self.curb_ascend_btn,
                self.dev_mode_btn,
                self.reset_btn,
            ]

            # Get the index of the currently highlighted button
            current_index = buttons.index(self.current_button)

            if direction == "Neutral":
                pass
            elif direction == "Left":
                # Cycle left
                current_index = (current_index - 1) % len(buttons)
            elif direction == "Right":
                # Cycle right
                current_index = (current_index + 1) % len(buttons)
            elif direction == "Forward":
                # Set all buttons to default color
                for button in buttons:
                    button.setBackgroundColor("Default")

                # Set the color of the current nested_button to green
                if self.current_button == self.elevate_btn:
                    self.raise_up_btn.setBackgroundColor("LightGreen")
                    self.lower_down_btn.setBackgroundColor("Default")
                elif self.current_button == self.lean_btn:
                    self.lean_forward_btn.setBackgroundColor("LightGreen")
                    self.lean_backward_btn.setBackgroundColor("Default")
                elif self.current_button == self.tilt_btn:
                    self.tilt_left_btn.setBackgroundColor("LightGreen")
                    self.tilt_right_btn.setBackgroundColor("Default")
                elif self.current_button == self.carriage_btn:
                    self.carriage_forward_btn.setBackgroundColor("LightGreen")
                    self.carriage_backward_btn.setBackgroundColor("Default")
                elif self.current_button == self.self_leveling_btn:
                    self.self_leveling_btn.setBackgroundColor("LightRed")
                elif self.current_button == self.curb_ascend_btn:
                    self.curb_ascend_up_btn.setBackgroundColor("LightGreen")
                    self.curb_ascend_down_btn.setBackgroundColor("Default")
                elif self.current_button == self.reset_btn:
                    self.reset_btn.setBackgroundColor("LightRed")

                # Reset the flag after updating button color
                self.update_button_color_flag = False
                return
            elif direction == "Reverse":
                # Set all buttons to default color
                for button in buttons:
                    button.setBackgroundColor("Default")

                # Set the color of the current nested_button to green
                if self.current_button == self.elevate_btn:
                    self.raise_up_btn.setBackgroundColor("Default")
                    self.lower_down_btn.setBackgroundColor("LightYellow")
                elif self.current_button == self.lean_btn:
                    self.lean_forward_btn.setBackgroundColor("Default")
                    self.lean_backward_btn.setBackgroundColor("LightYellow")
                elif self.current_button == self.tilt_btn:
                    self.tilt_left_btn.setBackgroundColor("Default")
                    self.tilt_right_btn.setBackgroundColor("LightYellow")
                elif self.current_button == self.carriage_btn:
                    self.carriage_forward_btn.setBackgroundColor("Default")
                    self.carriage_backward_btn.setBackgroundColor("LightYellow")
                elif self.current_button == self.self_leveling_btn:
                    self.self_leveling_btn.setBackgroundColor("LightRed")
                elif self.current_button == self.curb_ascend_btn:
                    self.curb_ascend_up_btn.setBackgroundColor("Default")
                    self.curb_ascend_down_btn.setBackgroundColor("LightYellow")
                elif self.current_button == self.reset_btn:
                    self.reset_btn.setBackgroundColor("LightRed")

                # Reset the flag after updating button color
                self.update_button_color_flag = False
                return

            # Reset all buttons to default color
            for button in buttons:
                button.setBackgroundColor("Default")
            self.raise_up_btn.setBackgroundColor("Default")
            self.lower_down_btn.setBackgroundColor("Default")
            self.lean_forward_btn.setBackgroundColor("Default")
            self.lean_backward_btn.setBackgroundColor("Default")
            self.tilt_left_btn.setBackgroundColor("Default")
            self.tilt_right_btn.setBackgroundColor("Default")
            self.carriage_forward_btn.setBackgroundColor("Default")
            self.carriage_backward_btn.setBackgroundColor("Default")
            self.curb_ascend_up_btn.setBackgroundColor("Default")
            self.curb_ascend_down_btn.setBackgroundColor("Default")

            # Set the color of the button corresponding to the updated index
            buttons[current_index].setBackgroundColor("LightBlue")

            # Update the current button
            self.current_button = buttons[current_index]

            # Reset the flag after updating button color
            self.update_button_color_flag = False

            # Debug statement to print the index of the button being selected
            print("Navigating to button:", current_index)

        except Exception as e:
            print("Error in update_button_color:", e)
            traceback.print_exc()

    def carriage_backward_pressed(self):
        try:
            if self.carriage_state == "Rear-Wheel Drive":
                self.carriage_state = "Rear-Wheel Drive"
            elif self.carriage_state == "Mid-Wheel Drive":
                self.carriage_state = "Rear-Wheel Drive"
            elif self.carriage_state == "Front-Wheel Drive":
                self.carriage_state = "Mid-Wheel Drive"

            self.teensy_controller.carriage_backward_pressed()

            self.carriage_label.setText("Carriage State: " + self.carriage_state)

        except Exception as e:
            print("Error in carriage_forward_and_backward_pressed:", e)
            traceback.print_exc()

    def carriage_forward_pressed(self):
        try:
            if self.carriage_state == "Rear-Wheel Drive":
                self.carriage_state = "Mid-Wheel Drive"
            elif self.carriage_state == "Mid-Wheel Drive":
                self.carriage_state = "Front-Wheel Drive"
            elif self.carriage_state == "Front-Wheel Drive":
                self.carriage_state = "Front-Wheel Drive"

            self.teensy_controller.carriage_forward_pressed()

            self.carriage_label.setText("Carriage State: " + self.carriage_state)

        except Exception as e:
            print("Error in carriage_forward_and_backward_pressed:", e)
            traceback.print_exc()
